'use client'

import { useState } from 'react'
import Box from '@mui/material/Box'
import Typography from '@mui/material/Typography'
import { Icon } from '@iconify/react'
import SectionHeading from '../ui/SectionHeading'
import { FAQ } from '../data/landing.data'
import { SECTION_IDS } from '@/utils/constant'

export default function FaqSection() {
  const [openIndex, setOpenIndex] = useState<number | null>(null)

  return (
    <Box
      id={SECTION_IDS.FAQ}
      className='landing-section'
      sx={{ backgroundColor: 'var(--surface-page)' }}
    >
      <Box className='landing-container'>
        <SectionHeading
          eyebrow={FAQ.eyebrow}
          title={FAQ.titleLeading}
          accent={FAQ.titleAccent}
          subtitle={FAQ.subtitle}
          size='md'
        />

        <Box sx={{ mt: { xs: 5, md: 7 }, maxWidth: 760, mx: 'auto' }}>
          {FAQ.items.map((item, i) => {
            const expanded = openIndex === i
            return (
              <Box
                key={item.question}
                sx={{
                  borderBottom: '1px solid var(--divider)',
                }}
              >
                <Box
                  component='button'
                  type='button'
                  onClick={() => setOpenIndex(expanded ? null : i)}
                  sx={{
                    width: '100%',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    gap: 2,
                    py: 2,
                    px: 0,
                    backgroundColor: 'transparent',
                    border: 'none',
                    cursor: 'pointer',
                    color: 'var(--text-strong)',
                    fontFamily: 'inherit',
                    textAlign: 'left',
                    transition: 'color 0.15s ease',
                    '&:hover': { color: 'var(--brand-primary-hover)' },
                  }}
                >
                  <Typography variant='Body/M-SemiBold' sx={{ color: 'inherit' }}>
                    {item.question}
                  </Typography>
                  <Icon
                    icon='mdi:chevron-down'
                    fontSize={18}
                    style={{
                      transition: 'transform 0.2s ease',
                      transform: expanded ? 'rotate(180deg)' : 'rotate(0)',
                    }}
                  />
                </Box>
                <Box
                  sx={{
                    overflow: 'hidden',
                    maxHeight: expanded ? 200 : 0,
                    transition: 'max-height 0.25s ease',
                  }}
                >
                  <Typography
                    variant='Body/S-Regular'
                    sx={{ color: 'var(--text-secondary)', pb: 2, lineHeight: 1.6, maxWidth: 640 }}
                  >
                    {item.answer}
                  </Typography>
                </Box>
              </Box>
            )
          })}
        </Box>
      </Box>
    </Box>
  )
}
